      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器组件，子组件依次入栈后入覆盖前入，支持对齐方式和同步加载属性",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Flex",
      "purpose": "弹性布局容器组件，支持主轴/交叉轴方向排列、多行换行、justifyContent/alignItems/space等完整flex属性",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动容器组件，支持垂直/水平/自由滚动，边缘效果、限位滚动、滚动控制器",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件，自动填充Row/Column/Flex父容器主轴剩余空间，支持最小尺寸和填充颜色",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件，分割不同内容块，支持水平/垂直方向、颜色、宽度、端点样式",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Tabs",
      "purpose": "页签内容切换容器组件，通过BarPosition/barMode/barWidth/barHeight等控制TabBar，配合TabContent使用",
      "anchor": "tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "仅在Tabs组件中使用的页签内容视图，通过tabBar属性设置显示内容（支持字符串、资源、SubTabBarStyle、BottomTabBarStyle等）",
      "anchor": "tabcontent",
      "status": "found"
    },
    {
      "name": "Navigation",
      "purpose": "路由导航根视图容器，支持NavPathStack管理页面栈、标题栏、工具栏、分栏/单栏显示模式",
      "anchor": "navigation",
      "status": "found"
    },
    {
      "name": "NavPathStack",
      "purpose": "导航控制器，以栈结构管理Navigation子页面，提供pushPath/pushPathByName/pop/popToName/replacePath/removeByName等页面切换方法",
      "anchor": "navpathstack10",
      "status": "found"
    }
